import sys
import math

def solve() -> None:
    data = list(map(int, sys.stdin.buffer.read().split()))
    it = iter(data)
    t = next(it)
    out_lines = []
    for _ in range(t):
        n = next(it)
        cnt = [0] * 30
        for _ in range(n):
            v = next(it)
            b = 0
            while v:
                if v & 1:
                    cnt[b] += 1
                v >>= 1
                b += 1
        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)
        if g == 0:          # all numbers are zero
            out_lines.append(' '.join(str(k) for k in range(1, n + 1)))
        else:
            divs = []
            d = 1
            while d * d <= g:
                if g % d == 0:
                    divs.append(d)
                    if d * d != g:
                        divs.append(g // d)
                d += 1
            divs.sort()
            out_lines.append(' '.join(map(str, divs)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

