def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        max_diff = 0
        for i in range(1, n + 1):
            a = int(next(it))
            diff = a - i
            if diff > max_diff:
                max_diff = diff
        out_lines.append(str(max_diff if max_diff > 0 else 0))
    sys.stdout.write("\n".join(out_lines))

