import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    pow10 = [1]
    for _ in range(7):
        pow10.append(pow10[-1] * 10)

    out_lines = []
    for _ in range(t):
        x1 = int(next(it)); p1 = int(next(it))
        x2 = int(next(it)); p2 = int(next(it))

        d1 = len(str(x1))
        d2 = len(str(x2))
        len1 = d1 + p1
        len2 = d2 + p2

        if len1 < len2:
            out_lines.append('<')
        elif len1 > len2:
            out_lines.append('>')
        else:
            diff = p1 - p2
            if diff > 0:
                x2_adj = x2 * pow10[diff]
                if x1 < x2_adj:
                    out_lines.append('<')
                elif x1 > x2_adj:
                    out_lines.append('>')
                else:
                    out_lines.append('=')
            elif diff < 0:
                x1_adj = x1 * pow10[-diff]
                if x1_adj < x2:
                    out_lines.append('<')
                elif x1_adj > x2:
                    out_lines.append('>')
                else:
                    out_lines.append('=')
            else:
                if x1 < x2:
                    out_lines.append('<')
                elif x1 > x2:
                    out_lines.append('>')
                else:
                    out_lines.append('=')

    sys.stdout.write('\n'.join(out_lines))

