    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    idx = 1
    for _ in range(t):
        s = data[idx]
        idx += 1
        n = len(s)
        if n % 2 == 0 and s[:n//2] == s[n//2:]:
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

