import sys

class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.sz = [1] * n

    def find(self, x):
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def unite(self, a, b):
        a = self.find(a)
        b = self.find(b)
        if a == b:
            return
        if self.sz[a] < self.sz[b]:
            a, b = b, a
        self.parent[b] = a
        self.sz[a] += self.sz[b]

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out_lines = []
    idx = 1
    for _ in range(t):
        s = data[idx]
        idx += 1
        n = len(s)
        dsu = DSU(n)
        for i, ch in enumerate(s):
            if ch == 'E':
                dsu.unite(i, (i + 1) % n)
        possible = True
        for i, ch in enumerate(s):
            if ch == 'N':
                if dsu.find(i) == dsu.find((i + 1) % n):
                    possible = False
                    break
        out_lines.append("YES" if possible else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

